```class Solution {
    public long waysToBuyPensPencils(int total, int cost1, int cost2) {
        int n = (total - cost1 - cost2) / (cost1 / cost2);
        return (total == 0 || cost1 == 0 || cost2 == 0) ? 1 : factorial(n) * (factorial(cost1) * factorial(cost2));
    }

    public long factorial(int n) {
        if (n == 0) {
            return 1;
        }
        return n * factorial(n - 1);
    }
}
